    22→data class HomeUiState(
    23→    val url: String = "",
    24→    val selectedLang: String = "en",
    25→    val isDownloading: Boolean = false,
    26→    val downloadProgress: Float = 0f,
    27→    val statusText: String = "",
    28→    val videos: List<VideoEntity> = emptyList(),
