   166→    fun importVideo(context: Context, uri: Uri, onComplete: (String, String?) -> Unit) {
   167→        viewModelScope.launch(Dispatchers.IO) {
   168→            try {
   169→                _uiState.update { it.copy(statusText = "正在导入..." ) }
   170→
   171→                val fileName = getFileName(context, uri) ?: "import_${System.currentTimeMillis()}.mp4"
   172→                val tempFile = File(downloadsDir, fileName)
   173→
   174→                val inputStream = context.contentResolver.openInputStream(uri)
   175→                val outputStream = FileOutputStream(tempFile)
   176→
   177→                inputStream?.use { input ->
   178→                    outputStream.use { output ->
   179→                        input.copyTo(output)
   180→                    }
   181→                }
   182→
   183→                val entity = VideoEntity(
   184→                    title = tempFile.nameWithoutExtension,
   185→                    filePath = tempFile.absolutePath,
   186→                    vttPath = null,
   187→                    language = _uiState.value.selectedLang,
   188→                    sourceUrl = null
   189→                )
   190→                videoRepository.insert(entity)
   191→
   192→                _uiState.update { it.copy(statusText = "导入完成!", url = "") }
   193→                launch(Dispatchers.Main) { onComplete(tempFile.absolutePath, null) }
   194→            } catch (e: Exception) {
   195→                android.util.Log.e("MultiLangLearner", "Import failed", e)
   196→                _uiState.update { it.copy(statusText = "导入失败: ${e.message}") }
   197→            }
   198→        }
   199→    }
   200→
   201→    private fun getFileName(context: Context, uri: Uri): String? {
   202→        var result: String? = null
   203→        if (uri.scheme == "content") {
   204→            val cursor = context.contentResolver.query(uri, null, null, null, null)
   205→            cursor?.use {
   206→                if (it.moveToFirst()) {
   207→                    val index = it.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
   208→                    if (index >= 0) result = it.getString(index)
   209→                }
   210→            }
   211→        }
   212→        if (result == null) {
   213→            result = uri.path
   214→            val cut = result?.lastIndexOf('/')
   215→            if (cut != -1) {
   216→                result = result?.substring(cut!! + 1)
   217→            }
   218→        }
   219→        return result
   220→    }
   221→}
