/**
 * 下载视频 - 支持 B站、YouTube 等平台
 * 使用新的分段下载服务，支持断点续传
 */
fun downloadVideo(onComplete: (String, String?) -> Unit) {
    val url = _uiState.value.url.trim()

    if (url.isBlank()) {
        updateCurrentDownload(DownloadTask(url = url, title = "", errorMessage = "请输入视频链接"))
        return
    }

    // 如果已有下载在进行，加入队列
    if (_uiState.value.isProcessing) {
        addToQueue(url)
        return
    }

    startDownload(url, onComplete)
}

/**
 * 开始下载
 */
private fun startDownload(url: String, onComplete: (String, String?) -> Unit) {
    viewModelScope.launch(Dispatchers.IO) {
        try {
            // 创建下载任务
            val task = DownloadTask(
                url = url,
                title = "正在解析...",
                status = DownloadStatus.FETCHING_INFO
            )
            updateCurrentDownload(task)

            // 获取视频信息
            val result = videoDownloadService.getVideoInfo(url)

            result.onSuccess { videoInfo ->
                // 更新任务信息
                val updatedTask = task.copy(
                    title = videoInfo.title,
                    status = DownloadStatus.DOWNLOADING
                )
                updateCurrentDownload(updatedTask)

                // 生成文件名
                val safeTitle = videoInfo.title.replace(Regex("[\\\\/:*?\"<>|]"), "_").take(50)
                val outputFile = File(downloadsDir, "${safeTitle}_${System.currentTimeMillis()}.mp4")

                // 使用分段下载器下载
                downloadWithSegmentedDownloader(videoInfo.downloadUrl, safeTitle, outputFile, onComplete)
            }.onFailure { error ->
                val failedTask = currentDownloadTask?.copy(
                    status = DownloadStatus.FAILED,
                    errorMessage = "解析失败: ${error.message}\n\n建议：使用导入功能添加本地视频",
                    errorCode = error.javaClass.simpleName
                )
                updateCurrentDownload(failedTask)
                addToHistory(failedTask!!)
            }

        } catch (e: Exception) {
            android.util.Log.e("HomeViewModel", "Download failed", e)
            val failedTask = currentDownloadTask?.copy(
                status = DownloadStatus.FAILED,
                errorMessage = "下载失败: ${e.message}",
                errorCode = e.javaClass.simpleName
            )
            updateCurrentDownload(failedTask)
            addToHistory(failedTask!!)
        }
    }
}

/**
 * 使用分段下载器下载视频
 */
private suspend fun downloadWithSegmentedDownloader(
    videoUrl: String,
    title: String,
    outputFile: File,
    onComplete: (String, String?) -> Unit
) {
    val startTime = System.currentTimeMillis()
    var lastUpdate = startTime

    try {
        val config = SegmentedDownloader.DownloadConfig(
            url = videoUrl,
            outputFile = outputFile,
            enableResume = true,
            onProgress = { progress ->
                val now = System.currentTimeMillis()
                // 限制更新频率（每200ms更新一次）
                if (now - lastUpdate > 200) {
                    val elapsedSeconds = (now - startTime) / 1000.0
                    val speed = progress.speed
                    val remainingBytes = progress.totalBytes - progress.bytesDownloaded
                    val remainingTime = if (speed > 0) remainingBytes / speed else 0L

                    val updatedTask = currentDownloadTask?.copy(
                        status = DownloadStatus.DOWNLOADING,
                        progress = progress.percent,
                        bytesDownloaded = progress.bytesDownloaded,
                        totalBytes = progress.totalBytes,
                        speed = speed,
                        remainingTime = remainingTime,
                        title = currentDownloadTask?.title ?: title
                    )
                    updateCurrentDownload(updatedTask)
                    lastUpdate = now
                }
            }
        )

        val result = segmentedDownloader.download(config)

        result.onSuccess { file ->
            val completedTask = currentDownloadTask?.copy(
                status = DownloadStatus.COMPLETED,
                progress = 100,
                completedAt = System.currentTimeMillis()
            )
            updateCurrentDownload(completedTask)

            // 保存到数据库
            val entity = VideoEntity(
                title = title,
                filePath = file.absolutePath,
                vttPath = null,
                language = _uiState.value.selectedLang,
                sourceUrl = currentDownloadTask?.url
            )
            videoRepository.insert(entity)

            // 添加到历史记录
            val history = DownloadHistory(
                id = completedTask?.id ?: UUID.randomUUID().toString(),
                title = title,
                url = currentDownloadTask?.url ?: "",
                filePath = file.absolutePath,
                fileSize = file.length(),
                status = DownloadStatus.COMPLETED,
                createdAt = completedTask?.createdAt ?: System.currentTimeMillis(),
                completedAt = completedTask?.completedAt
            )
            addToHistory(history)

            withContext(Dispatchers.Main) {
                onComplete(file.absolutePath, null)
                // 清除当前下载状态
                updateCurrentDownload(null)
            }
        }.onFailure { error ->
            val failedTask = currentDownloadTask?.copy(
                status = DownloadStatus.FAILED,
                errorMessage = "下载失败: ${error.message}",
                errorCode = error.javaClass.simpleName
            )
            updateCurrentDownload(failedTask)
            addToHistory(failedTask!!)
        }

    } catch (e: Exception) {
        android.util.Log.e("HomeViewModel", "Segmented download failed", e)
        val failedTask = currentDownloadTask?.copy(
            status = DownloadStatus.FAILED,
            errorMessage = "下载失败: ${e.message}",
            errorCode = e.javaClass.simpleName
        )
        updateCurrentDownload(failedTask)
        addToHistory(failedTask!!)
    }
}

