/**
 * 下载进度卡片组件
 */
@Composable
private fun DownloadProgressCard(
    task: DownloadTask,
    onCancel: () -> Unit,
    formatFileSize: (Long) -> String,
    formatSpeed: (Long) -> String,
    formatRemainingTime: (Long) -> String,
    getStatusText: (DownloadStatus) -> String
) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(
            containerColor = when (task.status) {
                DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.errorContainer
                else -> MaterialTheme.colorScheme.primaryContainer
            }
        )
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            // 标题和状态
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Column(Modifier.weight(1f)) {
                    Text(
                        task.title,
                        style = MaterialTheme.typography.titleSmall,
                        maxLines = 1,
                        overflow = TextOverflow.Ellipsis
                    )
                    Text(
                        getStatusText(task.status),
                        style = MaterialTheme.typography.bodySmall,
                        color = when (task.status) {
                            DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.error
                            else -> MaterialTheme.colorScheme.onPrimaryContainer
                        }
                    )
                }

                // 取消按钮
                if (task.status == DownloadStatus.DOWNLOADING || task.status == DownloadStatus.FETCHING_INFO) {
                    IconButton(onClick = onCancel) {
                        Icon(Icons.Default.Close, "取消", tint = MaterialTheme.colorScheme.error)
                    }
                }
            }

            Spacer(Modifier.height(12.dp))

            // 进度条
            if (task.status == DownloadStatus.DOWNLOADING) {
                Column {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween
                    ) {
                        Text(
                            "${task.progress}%",
                            style = MaterialTheme.typography.bodySmall
                        )
                        if (task.speed > 0) {
                            Text(
                                formatSpeed(task.speed),
                                style = MaterialTheme.typography.bodySmall,
                                color = MaterialTheme.colorScheme.primary
                            )
                        }
                    }

                    Spacer(Modifier.height(4.dp))

                    LinearProgressIndicator(
                        progress = { task.progress / 100f },
                        modifier = Modifier.fillMaxWidth(),
                        color = MaterialTheme.colorScheme.primary
                    )

                    // 文件大小和剩余时间
                    if (task.totalBytes > 0) {
                        Spacer(Modifier.height(4.dp))
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween
                        ) {
                            Text(
                                "${formatFileSize(task.bytesDownloaded)} / ${formatFileSize(task.totalBytes)}",
                                style = MaterialTheme.typography.bodySmall,
                                color = MaterialTheme.colorScheme.onPrimaryContainer
                            )
                            if (task.remainingTime > 0 && task.speed > 0) {
                                Text(
                                    "剩余 ${formatRemainingTime(task.remainingTime)}",
                                    style = MaterialTheme.typography.bodySmall,
                                    color = MaterialTheme.colorScheme.onPrimaryContainer
                                )
                            }
                        }
                    }
                }
            } else if (task.status == DownloadStatus.FETCHING_INFO) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    CircularProgressIndicator(
                        modifier = Modifier.size(20.dp),
                        strokeWidth = 2.dp
                    )
                    Spacer(Modifier.width(8.dp))
                    Text(
                        "正在解析视频信息...",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onPrimaryContainer
                    )
                }
            } else if (task.status == DownloadStatus.FAILED) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Icon(
                        Icons.Default.Error,
                        contentDescription = null,
                        tint = MaterialTheme.colorScheme.error,
                        modifier = Modifier.size(20.dp)
                    )
                    Spacer(Modifier.width(8.dp))
                    Text(
                        task.errorMessage ?: "下载失败",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.error
                    )
                }
            } else if (task.status == DownloadStatus.COMPLETED) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Icon(
                        Icons.Default.CheckCircle,
                        contentDescription = null,
                        tint = MaterialTheme.colorScheme.primary,
                        modifier = Modifier.size(20.dp)
                    )
                    Spacer(Modifier.width(8.dp))
                    Text(
                        "下载完成",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.primary
                    )
                }
            }
        }
    }
}

/**
 * 下载历史对话框
 */
@Composable
private fun DownloadHistoryDialog(
    history: List<DownloadHistory>,
    onDismiss: () -> Unit,
    onRetry: (String) -> Unit,
    onDelete: (String) -> Unit,
    onClear: () -> Unit,
    formatFileSize: (Long) -> String,
    getStatusText: (DownloadStatus) -> String
) {
    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("下载历史") },
        text = {
            if (history.isEmpty()) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(32.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text("暂无下载历史", color = MaterialTheme.colorScheme.onSurfaceVariant)
                }
            } else {
                LazyColumn(
                    verticalArrangement = Arrangement.spacedBy(8.dp),
                    modifier = Modifier.height(400.dp)
                ) {
                    items(history) { item ->
                        HistoryItem(
                            item = item,
                            onRetry = { onRetry(item.id) },
                            onDelete = { onDelete(item.id) },
                            formatFileSize = formatFileSize,
                            getStatusText = getStatusText
                        )
                    }
                }
            }
        },
        confirmButton = {
            if (history.isNotEmpty()) {
                TextButton(onClick = onClear) {
                    Text("清空历史")
                }
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) {
                Text("关闭")
            }
        }
    )
}

/**
 * 历史记录项
 */
@Composable
private fun HistoryItem(
    item: DownloadHistory,
    onRetry: () -> Unit,
    onDelete: () -> Unit,
    formatFileSize: (Long) -> String,
    getStatusText: (DownloadStatus) -> String
) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        colors = CardDefaults.cardColors(
            containerColor = when (item.status) {
                DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.errorContainer
                DownloadStatus.COMPLETED -> MaterialTheme.colorScheme.primaryContainer
                else -> MaterialTheme.colorScheme.surfaceVariant
            }
        )
    ) {
        Column(modifier = Modifier.padding(12.dp)) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Column(Modifier.weight(1f)) {
                    Text(
                        item.title,
                        style = MaterialTheme.typography.bodyMedium,
                        maxLines = 1,
                        overflow = TextOverflow.Ellipsis
                    )
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Surface(
                            color = when (item.status) {
                                DownloadStatus.COMPLETED -> Color(0xFF4CAF50)
                                DownloadStatus.FAILED -> Color(0xFFF44336)
                                DownloadStatus.CANCELLED -> Color(0xFFFF9800)
                                else -> MaterialTheme.colorScheme.secondary
                            },
                            shape = CircleShape
                        ) {
                            Box(
                                modifier = Modifier.padding(4.dp),
                                contentAlignment = Alignment.Center
                            ) {
                                when (item.status) {
                                    DownloadStatus.COMPLETED -> Icon(
                                        Icons.Default.Check,
                                        null,
                                        Modifier.size(12.dp),
                                        tint = Color.White
                                    )
                                    DownloadStatus.FAILED -> Icon(
                                        Icons.Default.Close,
                                        null,
                                        Modifier.size(12.dp),
                                        tint = Color.White
                                    )
                                    else -> Icon(
                                        Icons.Default.MoreHoriz,
                                        null,
                                        Modifier.size(12.dp),
                                        tint = Color.White
                                    )
                                }
                            }
                        }
                        Text(
                            getStatusText(item.status),
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }

                // 操作按钮
                Row {
                    if (item.status == DownloadStatus.FAILED) {
                        IconButton(onClick = onRetry, modifier = Modifier.size(36.dp)) {
                            Icon(Icons.Default.Refresh, "重试", Modifier.size(18.dp))
                        }
                    }
                    IconButton(onClick = onDelete, modifier = Modifier.size(36.dp)) {
                        Icon(Icons.Default.Delete, "删除", Modifier.size(18.dp))
                    }
                }
            }

            // 文件信息
            if (item.fileSize > 0) {
                Spacer(Modifier.height(4.dp))
                Text(
                    formatFileSize(item.fileSize),
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }

            // 时间信息
            val dateFormat = SimpleDateFormat("MM-dd HH:mm", Locale.getDefault())
            Spacer(Modifier.height(4.dp))
            Text(
                dateFormat.format(Date(item.createdAt)),
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )
        }
    }
}
